/*
     SQL ID : MsgShrtntDAO.updateShrtntRcvrDelyn
     설  명 : 쪽지 수신자 삭제 (논리)
 */
UPDATE TB_LMS_MSG_SHRTNT_SNDNG
SET RCVR_DELYN = 'Y'
WHERE MSG_SHRTNT_SNDNG_ID = #{msgShrtntSndngId}
  AND RCVR_ID = #{rcvrId}

mapper.select:
/* SQL ID : MsgShrtntDAO.selectShrtntSndngRcvrList 설 명 : 쪽지 발신 수신자 목록 조회 */ SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT S.MSG_SHRTNT_SNDNG_ID , S.RCVR_ID , U.USERNM AS RCVRNM , T.READ_DTTM , T.READ_YN , U.STDNT_NO , U.USER_ID AS USER_RPRS_ID2 , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = S.RCVR_ID AND UC.CNTCT_TYCD = 'MBL_PHN') AS MBL_PHN , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = S.RCVR_ID AND UC.CNTCT_TYCD = 'INDV_EML') AS EML , S.SNDNGYN AS SNDNG_YN FROM TB_LMS_MSG_SHRTNT_SNDNG S LEFT JOIN TB_LMS_USER U ON S.RCVR_ID = U.USER_ID LEFT JOIN TB_LMS_MSG_RCV_TRGTR T ON S.MSG_ID = T.MSG_ID AND S.RCVR_ID = T.USER_ID WHERE S.MSG_ID = #{msgId}
AND EXISTS (SELECT 1 FROM TB_LMS_MSG M WHERE M.MSG_ID = S.MSG_ID AND M.RGTR_ID = #{sndngrId})
ORDER BY U.USERNM ASC ) A WHERE ROWNUM <= #{lastIndex} ) WHERE RNUM >= #{firstIndex}

