/*
     SQL ID : MsgShrtntDAO.updateShrtntSndngrDelyn
     설  명 : 쪽지 발신자 삭제 (논리)
 */
UPDATE TB_LMS_MSG_SHRTNT_SNDNG
SET SNDNGR_DELYN = 'Y'
WHERE MSG_ID = #{msgId}
  AND SNDNGR_ID = #{sndngrId}

mapper.select:
/* SQL ID : MsgShrtntDAO.selectShrtntSndngRcvrExcelList 설 명 : 쪽지 발신 수신자 엑셀 목록 조회 */ SELECT ROW_NUMBER() OVER (ORDER BY U.USERNM ASC) AS RNUM , S.RCVR_ID , U.USERNM AS RCVRNM , U.STDNT_NO , U.USER_ID AS USER_RPRS_ID2 , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = S.RCVR_ID AND UC.CNTCT_TYCD = 'MBL_PHN') AS MBL_PHN , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = S.RCVR_ID AND UC.CNTCT_TYCD = 'INDV_EML') AS EML , S.SNDNGYN AS SNDNG_YN , T.READ_DTTM , T.READ_YN FROM TB_LMS_MSG_SHRTNT_SNDNG S LEFT JOIN TB_LMS_USER U ON S.RCVR_ID = U.USER_ID LEFT JOIN TB_LMS_MSG_RCV_TRGTR T ON S.MSG_ID = T.MSG_ID AND S.RCVR_ID = T.USER_ID WHERE S.MSG_ID = #{msgId}
AND EXISTS (SELECT 1 FROM TB_LMS_MSG M WHERE M.MSG_ID = S.MSG_ID AND M.RGTR_ID = #{sndngrId})
ORDER BY U.USERNM ASC

mapper.insert:
/*
     SQL ID : MsgShrtntDAO.insertMsg
     설  명 : 메시지 등록
 */
INSERT INTO TB_LMS_MSG (
                         MSG_ID
                       , MSG_TMPLT_ID
                       , MSG_TYCD
                       , MSG_CTS_GBNCD
                       , SBJCT_ID
                       , DGRS_YR
                       , SMSTR
                       , TTL
                       , TXT_CTS
                       , HTML_CTS
                       , RSRV_SNDNG_SDTTM
                       , RGTR_ID
                       , REG_DTTM
) VALUES (
           #{msgId}
         , #{msgTmpltId}
         , #{msgTycd}
         , 'INDV_MSG'
         , #{sbjctId}
         , #{dgrsYr}
         , #{smstr}
         , #{ttl}
         , #{txtCts}
         , #{htmlCts}
         , #{rsrvSndngSdttm}
         , #{rgtrId}
         , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
         )

/*
     SQL ID : MsgShrtntDAO.insertRcvTrgtr
     설  명 : 수신 대상자 등록
 */
INSERT INTO TB_LMS_MSG_RCV_TRGTR (
                                   MSG_ID
                                 , USER_ID
                                 , RCVRNM
                                 , RGTR_ID
                                 , REG_DTTM
) VALUES (
           #{msgId}
         , #{rcvrId}
         , #{rcvrnm}
         , #{rgtrId}
         , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
         )

/*
     SQL ID : MsgShrtntDAO.insertShrtntSndng
     설  명 : 쪽지 발송 등록
 */
INSERT INTO TB_LMS_MSG_SHRTNT_SNDNG (
                                      MSG_SHRTNT_SNDNG_ID
                                    , MSG_ID
                                    , UP_MSG_SHRTNT_SNDNG_ID
                                    , SNDNG_TTL
                                    , SNDNG_CTS
                                    , SNDNG_DTTM
                                    , SNDNGR_ID
                                    , SNDNGNM
                                    , RCVR_ID
                                    , SNDNGYN
                                    , SNDNGR_DELYN
                                    , RCVR_DELYN
                                    , RGTR_ID
                                    , REG_DTTM
) VALUES (
           #{msgShrtntSndngId}
         , #{msgId}
         , #{upMsgShrtntSndngId}
         , #{sndngTtl}
         , #{sndngCts}
         , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
         , #{sndngrId}
         , #{sndngnm}
         , #{rcvrId}
         , #{sndngYn}
         , 'N'
         , 'N'
         , #{rgtrId}
         , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
         )

