/*
     SQL ID : MsgShrtntDAO.updateMsg
     설  명 : 메시지 수정
 */
UPDATE TB_LMS_MSG
SET TTL = #{ttl}
  , TXT_CTS = #{txtCts}
  , HTML_CTS = #{htmlCts}
  , RSRV_SNDNG_SDTTM = #{rsrvSndngSdttm}
  , SBJCT_ID = #{sbjctId}
  , DGRS_YR = #{dgrsYr}
  , SMSTR = #{smstr}
  , MDFR_ID = #{mdfrId}
  , MOD_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
WHERE MSG_ID = #{msgId}

    AND RGTR_ID = #{sndngrId}

/*
     SQL ID : MsgShrtntDAO.updateMsgRsrvCncl
     설  명 : 예약 발신 취소
 */
UPDATE TB_LMS_MSG
SET RSRV_SNDNG_CNCL_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
  , MDFR_ID = #{mdfrId}
  , MOD_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
WHERE MSG_ID = #{msgId}
  AND RSRV_SNDNG_SDTTM IS NOT NULL
  AND RSRV_SNDNG_CNCL_DTTM IS NULL

    AND RGTR_ID = #{sndngrId}

mapper.select:
/* SQL ID : MsgShrtntDAO.selectMsgRcvTrgtrList 설 명 : 수신 대상자 목록 조회 */ SELECT T.USER_ID AS RCVR_ID , U.USERNM AS RCVRNM FROM TB_LMS_MSG_RCV_TRGTR T INNER JOIN TB_LMS_USER U ON T.USER_ID = U.USER_ID WHERE T.MSG_ID = #{msgId}
AND EXISTS (SELECT 1 FROM TB_LMS_MSG M WHERE M.MSG_ID = T.MSG_ID AND M.RGTR_ID = #{sndngrId})
ORDER BY U.USERNM ASC

/* SQL ID : MsgShrtntDAO.selectShrtntYrList 설 명 : 쪽지 학사년도 목록 조회 */ SELECT DISTINCT S.SBJCT_YR FROM TB_LMS_SBJCT S INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID
INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}
WHERE D.ORG_ID = #{orgId} AND S.DELYN = 'N' ORDER BY S.SBJCT_YR DESC

/*
SQL ID : MsgShrtntDAO.selectShrtntSmstrList
설  명 : 쪽지 학기 목록 조회
*/
SELECT DISTINCT TRIM(S.SBJCT_SMSTR) AS SBJCT_SMSTR
FROM TB_LMS_SBJCT S
INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID

    INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}

WHERE D.ORG_ID = #{orgId}
AND S.DELYN = 'N'

    AND S.SBJCT_YR = #{sbjctYr}

ORDER BY TRIM(S.SBJCT_SMSTR) ASC

/* SQL ID : MsgShrtntDAO.selectShrtntDeptList 설 명 : 쪽지 학과 목록 조회 */ SELECT DISTINCT D.DEPT_ID , D.DEPTNM FROM TB_LMS_DEPT D
INNER JOIN TB_LMS_SBJCT S ON S.DEPT_ID = D.DEPT_ID AND S.DELYN = 'N' INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}
WHERE D.ORG_ID = #{orgId} ORDER BY D.DEPTNM ASC

/*
SQL ID : MsgShrtntDAO.selectShrtntSbjctList
설  명 : 쪽지 운영과목 목록 조회
*/
SELECT DISTINCT S.SBJCT_ID
, S.SBJCTNM
FROM TB_LMS_SBJCT S
INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID

    INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}

WHERE D.ORG_ID = #{orgId}
AND S.DELYN = 'N'

    AND S.SBJCT_YR = #{sbjctYr}


    AND TRIM(S.SBJCT_SMSTR) = TRIM(#{sbjctSmstr})


    AND S.DEPT_ID = #{deptId}

ORDER BY S.SBJCTNM ASC

/* SQL ID : MsgShrtntDAO.selectShrtntRcvrByUserIds 설 명 : 엑셀 업로드 수신자 조회 (아이디 목록 기준) */ SELECT U.USER_ID , U.USERNM , U.STDNT_NO , U.USER_ID AS USER_RPRS_ID2 , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = U.USER_ID AND UC.CNTCT_TYCD = 'MBL_PHN') AS MBL_PHN , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = U.USER_ID AND UC.CNTCT_TYCD = 'INDV_EML') AS EML FROM TB_LMS_USER U WHERE U.USER_ID IN
#{uid}
AND EXISTS (SELECT 1 FROM TB_LMS_USER_ORG UO WHERE UO.USER_ID = U.USER_ID AND UO.ORG_ID = #{orgId})
ORDER BY U.USERNM ASC
